import pydicom
import json

print("Testing existing bulk data functionality...")

# Test 1: Simple bulk data at top level
def bulk_data_reader(tag, vr, value):
    return b'test_data'

json_data = {
    "00091002": {"vr": "OB", "BulkDataURI": "https://a.dummy.url"}
}

ds = pydicom.dataset.Dataset.from_json(json.dumps(json_data), bulk_data_reader)
assert b'test_data' == ds[0x00091002].value
print("✓ Test 1 passed: Simple bulk data at top level works")

# Test 2: Bulk data in sequence
json_data_with_seq = {
    "00091001": {
        "vr": "SQ",
        "Value": [
            {
                "00091002": {"vr": "OB", "BulkDataURI": "https://a.dummy.url"}
            }
        ]
    }
}

ds2 = pydicom.dataset.Dataset.from_json(
    json.dumps(json_data_with_seq), 
    bulk_data_reader
)

# Check that the sequence was created
assert (0x00091001, 0x00091001) in ds2
assert ds2[0x00091001].VR == 'SQ'
assert len(ds2[0x00091001].value) == 1

# Check that bulk data in sequence was handled
seq_item = ds2[0x00091001].value[0]
assert (0x00091002, 0x00091002) in seq_item
assert seq_item[0x00091002].value == b'test_data'
print("✓ Test 2 passed: Bulk data in sequence works")

# Test 3: Nested sequences with bulk data
json_data_nested = {
    "00091001": {
        "vr": "SQ",
        "Value": [
            {
                "00091003": {
                    "vr": "SQ",
                    "Value": [
                        {
                            "00091002": {"vr": "OB", "BulkDataURI": "https://a.dummy.url"}
                        }
                    ]
                }
            }
        ]
    }
}

ds3 = pydicom.dataset.Dataset.from_json(
    json.dumps(json_data_nested), 
    bulk_data_reader
)

# Check nested structure
assert (0x00091001, 0x00091001) in ds3
outer_seq = ds3[0x00091001].value[0]
assert (0x00091003, 0x00091003) in outer_seq
inner_seq = outer_seq[0x00091003].value[0]
assert (0x00091002, 0x00091002) in inner_seq
assert inner_seq[0x00091002].value == b'test_data'
print("✓ Test 3 passed: Nested sequences with bulk data works")

print("\nAll existing functionality tests passed!")
EOF"}

